package school.sptech;import java.time.LocalDateTime;import java.time.LocalTime;import java.time.format.DateTimeFormatter;import java.util.concurrent.ThreadLocalRandom;public class LogJava {    /* Application log    /*O sleep thread pode ser interrompido por outra thread, então o throws InterruptedException    diz que o codigo deve continuar sendo executado mesmo se ele se deparar com outra thread*/    public static void main(String[] args) throws InterruptedException {        /*Fazer um appliccation log.        DATA E HORA | INFO / ERROR / WARNING | dashboard / user | MENSAGEM */        String nivel = "";        String modulo = "";        Integer numParaMensagem = -1;        String mensagem1 = " Erro ao conectar com o banco de dados ";        String mensagem2 = " Conexão com o banco de dados relaizada com sucesso ";        String mensagem3 = " Alguns dados não estão carregando ";        String mensagem4 = " Usuário autenticado ";        DateTimeFormatter horaFormatada = DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm:ss");                while (true) {                    LocalDateTime dataEHora = LocalDateTime.now();                    numParaMensagem = ThreadLocalRandom.current().nextInt(1,5);                    if (numParaMensagem == 1) {                        nivel = " ERROR ";                        modulo = " Dashboard ";                        System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|"+ modulo + "|"   + mensagem1);                    } else if (numParaMensagem == 2) {                        nivel = " INFO ";                        modulo = " Dashboard ";                        System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem2);                    } else if (numParaMensagem == 3){                        nivel = " WARNING ";                        modulo = " Dashboard ";                        System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem3);                    } else {                        nivel = " INFO ";                        modulo = " Usuário ";                        System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem4);                    }                    Thread.sleep(5000);                }            }        }